mapper.select:
select nickname
from tbl_member
where id = #{memberId}

select
    coalesce((
        select sum(w.view_count)
        from tbl_work w
        where w.member_id = #{memberId}
          and w.deleted_datetime is null
          and w.status != 'DELETED'
    ), 0) as total_views,
    coalesce((
        select count(*)
        from tbl_auction a
        where a.seller_id = #{memberId}
          and a.status = 'ACTIVE'
    ), 0) as active_auction_count,
    coalesce((
        select count(*)
        from tbl_auction a
        where a.seller_id = #{memberId}
          and a.status = 'SOLD'
    ), 0) as sold_auction_count,
    coalesce((
        select count(*)
        from tbl_auction a
        where a.seller_id = #{memberId}
    ), 0) as hosted_auction_count,
    coalesce((
        select sum(coalesce(a.final_price, a.current_price, a.asking_price))
        from tbl_auction a
        where a.seller_id = #{memberId}
          and a.status = 'SOLD'
    ), 0) as total_auction_transaction_amount,
    coalesce((
        select count(distinct ce.contest_id)
        from tbl_contest_entry ce
        join tbl_contest c on c.id = ce.contest_id
        where ce.member_id = #{memberId}
          and c.deleted_datetime is null
          and c.status not in ('DELETED', 'RESULT', 'CLOSED')
    ), 0) as participating_contest_count,
    coalesce((
        select count(*)
        from tbl_contest c
        where c.member_id = #{memberId}
          and c.deleted_datetime is null
          and c.status = 'OPEN'
    ), 0) as active_contest_count,
    coalesce((
        select count(*)
        from tbl_contest_entry ce
        where ce.member_id = #{memberId}
          and ce.award_rank is not null
    ), 0) as awarded_contest_count,
    coalesce((
        select sum(coalesce(c.price, 0))
        from tbl_contest c
        where c.member_id = #{memberId}
          and c.deleted_datetime is null
          and c.status != 'DELETED'
    ), 0) as total_contest_prize_amount,
    coalesce((
        select sum(p.total_price)
        from tbl_payment p
        where p.buyer_id = #{memberId}
          and p.status in ('PENDING', 'AUTHORIZED')
    ), 0) as pending_payment_amount,
    coalesce((
        select count(*)
        from tbl_auction a
        where a.seller_id = #{memberId}
          and a.status = 'ACTIVE'
          and a.closing_at between now() and now() + interval '1 day'
    ), 0) as closing_soon_auction_count,
    coalesce((
        select count(*)
        from tbl_payment p
        where p.buyer_id = #{memberId}
          and p.status in ('PENDING', 'AUTHORIZED')
    ), 0) as pending_payment_count,
    coalesce((
        select count(*)
        from tbl_settlement s
        where s.member_id = #{memberId}
          and s.status = 'PAID'
    ), 0) as completed_withdrawal_count,
    coalesce((
        select sum(s.net_amount)
        from tbl_settlement s
        where s.member_id = #{memberId}
          and s.status in ('PENDING', 'APPROVED')
    ), 0) as planned_settlement_amount,
    coalesce((
        select sum(p.total_price)
        from tbl_payment p
        where p.buyer_id = #{memberId}
           or p.seller_id = #{memberId}
    ), 0) as total_payment_amount,
    coalesce((
        select count(*)
        from tbl_payment p
        where (p.buyer_id = #{memberId} or p.seller_id = #{memberId})
          and p.status = 'COMPLETED'
    ), 0) as payment_success_count,
    coalesce((
        select count(*)
        from tbl_payment p
        where (p.buyer_id = #{memberId} or p.seller_id = #{memberId})
          and p.status in ('REFUNDED', 'CANCELLED')
    ), 0) as payment_failure_count,
    coalesce((
        select count(*)
        from tbl_settlement s
        where s.member_id = #{memberId}
          and s.status in ('PENDING', 'APPROVED')
    ), 0) as pending_settlement_count,
    coalesce((
        select count(*)
        from tbl_notification n
        where n.member_id = #{memberId}
          and n.is_read = false
    ), 0) as unread_notification_count
